/**
 * Permission Form Items Component
 *
 * IMPORTANT: All permission configurations and mappings in this file must stay
 * in sync with backend src/role.rs:
 * - Module definitions and their available permissions
 * - Permission levels (VIEW, EDIT, and fine-grained operations)
 *
 * Any changes to role.rs constants or valid_permissions() must be reflected here.
 *
 * Key System Design:
 * - Uses permId (number) directly as React keys for safety and performance
 * - permId = (module << 8) | level
 * - No string parsing/conversion - eliminates a major source of errors
 * - Direct mapping between frontend keys and backend permission IDs
 *
 */

import React, { useState, useEffect } from 'react';
import { Space, Typography, Card, Checkbox, theme, Tooltip } from 'antd';
import { QuestionCircleOutlined } from '@ant-design/icons';
import { t } from '../../global';
import {
  Module,
  Level,
  permId,
  parsePermId,
  getRecommendedPermissions,
  RoleType,
} from './permissionUtils';

const { Text } = Typography;
const { useToken } = theme;

type PermsFormItemsProps = {
  permissions: number[]; // Array of PermId
  setPermissions: React.Dispatch<React.SetStateAction<number[]>>;
  autoAddRecommended?: boolean; // Whether to auto-add recommended permissions
  onCountChange?: (count: number) => void; // Callback when selected count changes
  roleType?: RoleType; // Role type to filter available permissions
};

interface ModuleConfig {
  module: Module;
  label: string;
  // Permission level titles - use level number as key
  titles: Record<number, string>;
  // Permission level descriptions - use level number as key
  descriptions: Record<number, string>;
  // Available levels for this module
  availableLevels: number[];
}

const PermsFormItems: React.FC<PermsFormItemsProps> = ({
  permissions,
  setPermissions,
  autoAddRecommended = false,
  onCountChange,
  roleType = RoleType.GLOBAL,
}) => {
  const [checkedKeys, setCheckedKeys] = useState<React.Key[]>([]);
  // Track which permissions were auto-added by which parent permission
  // Map: childPermKey -> Set of parentPermKeys that auto-added it
  const [autoAddedBy, setAutoAddedBy] = useState<Map<React.Key, Set<React.Key>>>(new Map());
  const { token } = useToken();

  // Filter modules based on role type
  const getAvailableModules = (): Module[] => {
    switch (roleType) {
      case RoleType.GLOBAL:
        // Global type: All modules
        return [
          Module.USERS,
          Module.DEVICES,
          Module.USER_GROUPS,
          Module.DEVICE_GROUPS,
          Module.AUDIT_LOGS,
          Module.STRATEGIES,
          Module.CONTROL_ROLES,
          Module.CUSTOM_CLIENTS,
        ];
      case RoleType.INDIVIDUAL:
        // Individual type: Only Devices and Audits
        return [Module.DEVICES, Module.AUDIT_LOGS];
      case RoleType.GROUP_SCOPED:
        // Group Scoped type: Users and Devices
        return [Module.USERS, Module.DEVICES];
      default:
        return [];
    }
  };


  const modulesConfig: ModuleConfig[] = [
    {
      module: Module.USERS,
      label: t('Users', true) as string,
      availableLevels: [
        Level.VIEW,
        Level.USER_CREATE,
        Level.USER_INVITE,
        Level.USER_DELETE,
        Level.USER_ENABLE_DISABLE,
        Level.USER_EDIT_EMAIL,
        Level.USER_EDIT_PASSWORD,
        Level.USER_EDIT_NOTE,
        Level.USER_EDIT_DISPLAY_NAME,
        Level.USER_MANAGE_2FA,
        Level.USER_FORCE_LOGOUT,
        Level.USER_CHANGE_GROUP,
        Level.USER_CHANGE_STRATEGY,
        Level.USER_CHANGE_CONTROL_ROLE,
      ],
      titles: {
        [Level.VIEW]: t('View', true) as string,
        [Level.USER_CREATE]: t('Create', true) as string,
        [Level.USER_INVITE]: t('Invite', true) as string,
        [Level.USER_DELETE]: t('Delete', true) as string,
        [Level.USER_ENABLE_DISABLE]: t('Enable/Disable', true) as string,
        [Level.USER_EDIT_EMAIL]: t('Edit Email', true) as string,
        [Level.USER_EDIT_PASSWORD]: t('Edit Password', true) as string,
        [Level.USER_EDIT_NOTE]: t('Edit Note', true) as string,
        [Level.USER_EDIT_DISPLAY_NAME]: t('Edit Display Name', true) as string,
        [Level.USER_MANAGE_2FA]: t('Manage 2FA', true) as string,
        [Level.USER_FORCE_LOGOUT]: t('Force Logout', true) as string,
        [Level.USER_CHANGE_GROUP]: t('Update Group', true) as string,
        [Level.USER_CHANGE_STRATEGY]: t('Update Strategy', true) as string,
        [Level.USER_CHANGE_CONTROL_ROLE]: t('Update Control Role', true) as string,
      },
      descriptions: {
        [Level.VIEW]: 'view_users_permission_description',
        [Level.USER_CREATE]: 'user_create_permission_description',
        [Level.USER_INVITE]: 'user_invite_permission_description',
        [Level.USER_DELETE]: 'user_delete_permission_description',
        [Level.USER_ENABLE_DISABLE]: 'user_enable_disable_permission_description',
        [Level.USER_EDIT_EMAIL]: 'user_edit_email_permission_description',
        [Level.USER_EDIT_PASSWORD]: 'user_edit_password_permission_description',
        [Level.USER_EDIT_NOTE]: 'user_edit_note_permission_description',
        [Level.USER_EDIT_DISPLAY_NAME]: 'user_edit_display_name_permission_description',
        [Level.USER_MANAGE_2FA]: 'user_manage_2fa_permission_description',
        [Level.USER_FORCE_LOGOUT]: 'user_force_logout_permission_description',
        [Level.USER_CHANGE_GROUP]: 'user_change_group_permission_description',
        [Level.USER_CHANGE_STRATEGY]: 'user_change_strategy_permission_description',
        [Level.USER_CHANGE_CONTROL_ROLE]: 'user_change_control_role_permission_description',
      },
    },
    {
      module: Module.DEVICES,
      label: t('Devices', true) as string,
      availableLevels: [
        Level.VIEW,
        Level.DEVICE_ENABLE_DISABLE,
        Level.DEVICE_DELETE,
        Level.DEVICE_EDIT_INFO,
        Level.DEVICE_ASSIGN_TO_USER,
        Level.DEVICE_CHANGE_GROUP,
        Level.DEVICE_CHANGE_STRATEGY,
      ],
      titles: {
        [Level.VIEW]: t('View', true) as string,
        [Level.DEVICE_ENABLE_DISABLE]: t('Enable/Disable', true) as string,
        [Level.DEVICE_DELETE]: t('Delete', true) as string,
        [Level.DEVICE_EDIT_INFO]: t('Edit Info', true) as string,
        [Level.DEVICE_ASSIGN_TO_USER]: t('Assign to User', true) as string,
        [Level.DEVICE_CHANGE_GROUP]: t('Update Group', true) as string,
        [Level.DEVICE_CHANGE_STRATEGY]: t('Update Strategy', true) as string,
      },
      descriptions: {
        [Level.VIEW]: 'view_devices_permission_description',
        [Level.DEVICE_ENABLE_DISABLE]: 'device_enable_disable_permission_description',
        [Level.DEVICE_DELETE]: 'device_delete_permission_description',
        [Level.DEVICE_EDIT_INFO]: 'device_edit_info_permission_description',
        [Level.DEVICE_ASSIGN_TO_USER]: 'device_assign_to_user_permission_description',
        [Level.DEVICE_CHANGE_GROUP]: 'device_change_group_permission_description',
        [Level.DEVICE_CHANGE_STRATEGY]: 'device_change_strategy_permission_description',
      },
    },
    {
      module: Module.USER_GROUPS,
      label: t('User Groups', true) as string,
      availableLevels: [Level.VIEW, Level.EDIT],
      titles: {
        [Level.VIEW]: t('View', true) as string,
        [Level.EDIT]: t('Edit', true) as string,
      },
      descriptions: {
        [Level.VIEW]: 'view_user_groups_permission_description',
        [Level.EDIT]: 'edit_user_groups_permission_description',
      },
    },
    {
      module: Module.DEVICE_GROUPS,
      label: t('Device Groups', true) as string,
      availableLevels: [Level.VIEW, Level.EDIT, Level.DEVICE_GROUP_CHANGE_STRATEGY],
      titles: {
        [Level.VIEW]: t('View', true) as string,
        [Level.EDIT]: t('Edit', true) as string,
        [Level.DEVICE_GROUP_CHANGE_STRATEGY]: t('Update Strategy', true) as string,
      },
      descriptions: {
        [Level.VIEW]: 'view_device_groups_permission_description',
        [Level.EDIT]: 'edit_device_groups_permission_description',
        [Level.DEVICE_GROUP_CHANGE_STRATEGY]: 'device_group_change_strategy_permission_description',
      },
    },
    {
      module: Module.AUDIT_LOGS,
      label: t('Logs', true) as string,
      availableLevels: [Level.VIEW, Level.EDIT],
      titles: {
        [Level.VIEW]: t('View', true) as string,
        [Level.EDIT]: t('Edit', true) as string,
      },
      descriptions: {
        [Level.VIEW]: 'view_audits_permission_description',
        [Level.EDIT]: 'edit_audits_permission_description',
      },
    },
    {
      module: Module.STRATEGIES,
      label: t('Strategies', true) as string,
      availableLevels: [Level.VIEW, Level.EDIT],
      titles: {
        [Level.VIEW]: t('View', true) as string,
        [Level.EDIT]: t('Edit', true) as string,
      },
      descriptions: {
        [Level.VIEW]: 'view_strategies_permission_description',
        [Level.EDIT]: 'edit_strategies_permission_description',
      },
    },
    {
      module: Module.CONTROL_ROLES,
      label: t('Control Roles', true) as string,
      availableLevels: [Level.VIEW, Level.EDIT],
      titles: {
        [Level.VIEW]: t('View', true) as string,
        [Level.EDIT]: t('Edit', true) as string,
      },
      descriptions: {
        [Level.VIEW]: 'view_control_roles_permission_description',
        [Level.EDIT]: 'edit_control_roles_permission_description',
      },
    },
    {
      module: Module.CUSTOM_CLIENTS,
      label: t('Custom Clients', true) as string,
      availableLevels: [Level.VIEW, Level.EDIT],
      titles: {
        [Level.VIEW]: t('View', true) as string,
        [Level.EDIT]: t('Edit', true) as string,
      },
      descriptions: {
        [Level.VIEW]: 'view_custom_clients_permission_description',
        [Level.EDIT]: 'edit_custom_clients_permission_description',
      },
    },
  ];

  /**
   * Get permission key identifier
   * Returns the permission ID (number) that will be used as React key
   *
   * Using numeric permId as key is safer than string-based keys:
   * - No string parsing/splitting logic that could fail
   * - Direct mapping to backend permission IDs
   * - Better performance
   * - Easier to maintain and debug
   */
  const getPermissionKey = (module: Module, level: number): number => {
    // Return permId as the key (module << 8) | level
    return permId(module, level);
  };

  /**
   * Build permissions array from checked keys
   * Keys are permIds (numbers)
   */
  const buildPermissionsFromKeys = (keys: React.Key[]): number[] => {
    const newPermissions: number[] = [];

    keys.forEach((key) => {
      // Key is a permId (number)
      const keyNum = typeof key === 'number' ? key : parseInt(key.toString());
      if (isNaN(keyNum)) return;

      // Key is already a valid permId, just add it
      newPermissions.push(keyNum);
    });

    return newPermissions;
  };

  const handlePermissionToggle = (module: Module, level: number, checked: boolean) => {
    const key = getPermissionKey(module, level);
    if (!key) {
      return;
    }

    // checkedKeys contains permIds (numbers)
    const currentKeys = new Set(checkedKeys);
    const newAutoAddedBy = new Map(autoAddedBy);

    if (checked) {
      currentKeys.add(key);

      // If user manually checks this permission, clear its auto-added-by record
      // This means it's now a "wanted" permission, not just auto-added
      if (newAutoAddedBy.has(key)) {
        newAutoAddedBy.delete(key);
      }

      // Auto-add recommended permissions if enabled
      if (autoAddRecommended) {
        const recommended = getRecommendedPermissions(module, level, roleType);

        recommended.forEach((recPermId) => {
          const { module: recModule, level: recLevel } = parsePermId(recPermId);
          const recKey = getPermissionKey(recModule as Module, recLevel);
          if (recKey && !currentKeys.has(recKey)) {
            // Only add if not already present
            currentKeys.add(recKey);

            // Record that this permission was auto-added by the parent permission
            if (!newAutoAddedBy.has(recKey)) {
              newAutoAddedBy.set(recKey, new Set());
            }
            newAutoAddedBy.get(recKey)!.add(key);
          }
        });
      }
    } else {
      currentKeys.delete(key);

      // Auto-remove recommended permissions that were ONLY auto-added by this permission
      const recommended = getRecommendedPermissions(module, level, roleType);

      recommended.forEach((recPermId) => {
        const { module: recModule, level: recLevel } = parsePermId(recPermId);
        const recKey = getPermissionKey(recModule as Module, recLevel);
        if (recKey && newAutoAddedBy.has(recKey)) {
          const parents = newAutoAddedBy.get(recKey)!;
          parents.delete(key); // Remove this parent from the set

          // If no more parents auto-added this permission, remove it
          if (parents.size === 0) {
            currentKeys.delete(recKey);
            newAutoAddedBy.delete(recKey);
          }
        }
      });
    }

    const keysArray = Array.from(currentKeys);
    setCheckedKeys(keysArray);
    setAutoAddedBy(newAutoAddedBy);
    setPermissions(buildPermissionsFromKeys(keysArray));

    // Notify parent of count change
    if (onCountChange) {
      onCountChange(keysArray.length);
    }
  };

  /**
   * Get description translation key based on role type
   * Tries role-specific key first (_global, _group, _individual), falls back to base key
   */
  const getDescriptionKey = (baseKey: string, level: number): string => {
    // Map roleType to suffix
    const roleTypeSuffix: Record<RoleType, string> = {
      [RoleType.GLOBAL]: '_global',
      [RoleType.GROUP_SCOPED]: '_group_scoped',
      [RoleType.INDIVIDUAL]: '_individual',
    };

    const suffix = roleTypeSuffix[roleType];
    const roleSpecificKey = `${baseKey}${suffix}`;

    // Try role-specific translation first
    const roleSpecificTranslation = t(roleSpecificKey, true);
    if (roleSpecificTranslation && roleSpecificTranslation !== roleSpecificKey) {
      return roleSpecificKey;
    }

    // Fall back to base key
    return baseKey;
  };

  const buildModulePermissionRows = (modConfig: ModuleConfig) => {
    const rows: Array<{
      level: number;
      title: string;
      description?: string;
    }> = [];

    // Build rows dynamically based on availableLevels
    let levels = modConfig.availableLevels.sort((a, b) => a - b);

    // For INDIVIDUAL role type, Devices module only has EDIT (VIEW is implicit)
    if (roleType === RoleType.INDIVIDUAL && modConfig.module === Module.DEVICES) {
      levels = levels.filter((l) => l !== Level.VIEW);
    }

    // For non-GLOBAL role types, filter out DEVICE_ASSIGN_TO_USER, DEVICE_CHANGE_GROUP
    if (roleType !== RoleType.GLOBAL && modConfig.module === Module.DEVICES) {
      levels = levels.filter((l) =>
        l !== Level.DEVICE_ASSIGN_TO_USER &&
        l !== Level.DEVICE_CHANGE_GROUP
      );
    }

    // For GROUP role types, allow USER_CHANGE_CONTROLLED_STRATEGY and USER_CHANGE_CONTROLLING_STRATEGY
    // Only filter out USER_CHANGE_GROUP for non-GLOBAL
    if (roleType !== RoleType.GLOBAL && modConfig.module === Module.USERS) {
      levels = levels.filter((l) => l !== Level.USER_CHANGE_GROUP);
    }

    // For non-GLOBAL role types, filter out DEVICE_GROUP_CHANGE_STRATEGY
    if (roleType !== RoleType.GLOBAL && modConfig.module === Module.DEVICE_GROUPS) {
      levels = levels.filter((l) => l !== Level.DEVICE_GROUP_CHANGE_STRATEGY);
    }

    for (const level of levels) {
      // Use level number directly as key
      const title = modConfig.titles[level];
      const baseDescriptionKey = modConfig.descriptions[level];

      // Get role-specific description
      let description = '';
      if (baseDescriptionKey && baseDescriptionKey.trim()) {
        const roleSpecificKey = getDescriptionKey(baseDescriptionKey, level);
        const roleSpecificDesc = t(roleSpecificKey, true) as string;
        if (roleSpecificDesc && roleSpecificDesc !== roleSpecificKey) {
          description = roleSpecificDesc;
        } else {
          // Fallback to base key if role-specific doesn't exist
          const baseDesc = t(baseDescriptionKey, true) as string;
          if (baseDesc && baseDesc !== baseDescriptionKey) {
            description = baseDesc;
          }
        }
      }

      if (title) {
        rows.push({
          level,
          title,
          description,
        });
      }
    }

    return rows;
  };


  const tableStyles = `
    .perms-table {
      width: 100%;
      border-collapse: separate;
      border-spacing: 0;
      background: ${token.colorBgContainer};
      color: ${token.colorText};
    }
    .perms-table th {
      background: ${token.colorFillAlter};
      font-weight: 600;
      text-align: left;
      padding: 12px 16px;
      border-bottom: 1px solid ${token.colorBorderSecondary};
      color: ${token.colorTextHeading};
    }
    .perms-table td {
      border-bottom: 1px solid ${token.colorBorderSecondary};
      padding: 12px 16px;
      vertical-align: top;
      background: ${token.colorBgContainer};
    }
    .perms-table tr:last-child td {
      border-bottom: none;
    }
    .module-cell {
      width: 20%;
      background: ${token.colorFillTertiary};
      border-right: 1px solid ${token.colorBorderSecondary};
      color: ${token.colorText};
    }
    .permission-cell {
      width: 30%;
      border-right: 1px solid ${token.colorBorderSecondary};
    }
    .description-cell {
      width: 50%;
      color: ${token.colorTextSecondary};
      font-size: 13px;
      line-height: 1.6;
    }
    .permission-title {
      font-weight: 500;
      display: inline-flex;
      align-items: center;
    }
  `;

  // Convert permissions array to checked keys
  useEffect(() => {
    const keys: React.Key[] = [];

    permissions.forEach((perm) => {
      // Permission ID is already the key (module << 8) | level
      keys.push(perm);
    });

    setCheckedKeys(keys);

    // Notify parent of count change
    if (onCountChange) {
      onCountChange(keys.length);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [permissions]);

  // Check if a permission is checked
  const isPermissionChecked = (module: Module, level: number): boolean => {
    const key = getPermissionKey(module, level);
    if (!key) {
      return false;
    }
    return checkedKeys.includes(key);
  };

  return (
    <Space
      direction="vertical"
      size="middle"
      style={{ width: '100%', marginTop: 16 }}
    >
      <Card bordered={false} bodyStyle={{ padding: 0 }}>
        <style>{tableStyles}</style>
        <table className="perms-table">
          <thead>
            <tr>
              <th style={{ width: '20%' }} />
              <th style={{ width: '30%' }}>
                {t('Permissions', true)}{' '}
                <Tooltip title={t('permission_column_header_tooltip', true)}>
                  <QuestionCircleOutlined style={{ cursor: 'pointer', color: token.colorTextDescription }} />
                </Tooltip>
              </th>
              <th style={{ width: '50%' }}>
                {t('Description', true)}
              </th>
            </tr>
          </thead>
          <tbody>
            {modulesConfig
              .filter((modConfig) => getAvailableModules().includes(modConfig.module))
              .map((modConfig) => {
                const rows = buildModulePermissionRows(modConfig);
                return rows.map((row, rowIndex) => {
                  const permissionKey = getPermissionKey(modConfig.module, row.level);
                  const isChecked = isPermissionChecked(modConfig.module, row.level);
                  return (
                    <tr key={permissionKey}>
                      {rowIndex === 0 && (
                        <td className="module-cell" rowSpan={rows.length}>
                          <Text strong>{modConfig.label}</Text>
                          {modConfig.module === Module.USERS && (
                            <span>
                              {' '}
                              <Tooltip title={t('user_column_header_tooltip', true)}>
                                <QuestionCircleOutlined style={{ cursor: 'pointer', color: token.colorTextDescription }} />
                              </Tooltip>
                            </span>
                          )}
                        </td>
                      )}
                      <td className="permission-cell">
                        <Checkbox
                          checked={isChecked}
                          onChange={(e) =>
                            handlePermissionToggle(modConfig.module, row.level, e.target.checked)
                          }
                        >
                          <div className="permission-title">
                            {row.title}
                          </div>
                        </Checkbox>
                      </td>
                      <td className="description-cell">
                        {row.description && (
                          <div dangerouslySetInnerHTML={{ __html: row.description }} />
                        )}
                      </td>
                    </tr>
                  );
                });
              })}
          </tbody>
        </table>
      </Card>
    </Space>
  );
};

export default PermsFormItems;
