import { Steps, message, Button, Tabs, Checkbox, Select, Typography, Card, Space } from 'antd';
import React, { useRef, useState, useEffect } from 'react';
import type { ActionType } from '@ant-design/pro-table';
import type { ProFormInstance, SubmitterProps } from '@ant-design/pro-form';
import { ModalForm, ProFormText, ProFormTextArea, ProFormSelect } from '@ant-design/pro-form';
import { addAdminRole, updateAdminRole } from '@/services/api';
import type { API } from '@/services/typings';
import { t, GroupTypeUser, GroupTypeDevice, NamesPurpose_EditRole } from '../../global';
import PermsFormItems from './PermsFormItems';
import styles from './NewOrUpdateForm.less';
import { parsePermId, RoleType } from './permissionUtils';
import { fetchAllNames } from '../DeviceGroupList';
import { getRoleTypeName } from './index';

// Note: PermId format is (module << 8) | level

export { parsePermId };

export enum RoleContent {
  RoleName = 0,
  RolePerms = 1,
}

type NewOrUpdateFormProps = {
  isNew: boolean;
  visible: boolean;
  onVisibleChange: React.Dispatch<React.SetStateAction<boolean>>;
  actionRef: React.MutableRefObject<ActionType | undefined>;
  initialValues: API.AdminRoleListItem | undefined;
};

type FormStep = {
  formItems: React.ReactNode;
  submitterProps: SubmitterProps;
};

const ROLE_AUTO_ADD_RECOMMENDED_KEY = 'role_auto_add_recommended';

const roleTypeDescriptions: Record<RoleType, string> = {
  [RoleType.GLOBAL]: 'global_type_description',
  [RoleType.INDIVIDUAL]: 'individual_type_description',
  [RoleType.GROUP_SCOPED]: 'group_scoped_type_description',
};

const NewOrUpdateForm: React.FC<NewOrUpdateFormProps> = ({
  isNew,
  visible,
  onVisibleChange,
  actionRef,
  initialValues,
}) => {
  const formRef = useRef<ProFormInstance>();
  // Initialize state from initialValues if editing, or empty if creating
  const [name, setName] = useState<string>(initialValues?.name ?? '');
  const [note, setNote] = useState<string>(initialValues?.note ?? '');
  const [roleType, setRoleType] = useState<RoleType>(initialValues?.type ?? RoleType.GLOBAL);
  // Separate states for user groups and device groups
  const [selectedUserGroups, setSelectedUserGroups] = useState<string[]>(initialValues?.user_groups ?? []);
  const [selectedDeviceGroups, setSelectedDeviceGroups] = useState<string[]>(initialValues?.device_groups ?? []);
  const [includeUnassigned, setIncludeUnassigned] = useState<boolean>(initialValues?.unassigned ?? false);
  const [permissions, setPermissions] = useState<number[]>(initialValues?.permissions ?? []);
  const [step, setStep] = useState<number>(RoleContent.RoleName);
  const [loading, setLoading] = useState<boolean>(false);
  const [autoAddRecommended, setAutoAddRecommended] = useState<boolean>(() => {
    const saved = localStorage.getItem(ROLE_AUTO_ADD_RECOMMENDED_KEY);
    return saved !== null ? saved === 'true' : true;
  });
  const [selectedCount, setSelectedCount] = useState<number>(permissions.length);

  // State for group options
  const [allUserGroups, setAllUserGroups] = useState<string[]>([]);
  const [allDeviceGroups, setAllDeviceGroups] = useState<string[]>([]);
  const [userGroupOptions, setUserGroupOptions] = useState<string[]>([]);
  const [deviceGroupOptions, setDeviceGroupOptions] = useState<string[]>([]);
  // State for existing role names (for duplicate check)
  const [existingRoleNames, setExistingRoleNames] = useState<string[]>([]);

  // Fetch existing role names when creating
  useEffect(() => {
    if (visible && isNew) {
      fetchAllNames('%', 'roles', '').then((names) => {
        setExistingRoleNames(names);
      }).catch(() => {
        setExistingRoleNames([]);
      });
    }
  }, [visible, isNew]);

  // Fetch groups when roleType changes
  useEffect(() => {
    if (visible && roleType === RoleType.GROUP_SCOPED) {
      const fetchGroups = async () => {
        try {
          // Fetch both user groups and device groups for GROUP type
          const [userGroups, deviceGroups] = await Promise.all([
            fetchAllNames('%', 'grp', NamesPurpose_EditRole, GroupTypeUser),
            fetchAllNames('%', 'grp', NamesPurpose_EditRole, GroupTypeDevice),
          ]);
          setAllUserGroups(userGroups);
          setAllDeviceGroups(deviceGroups);
        } catch (error) {
          console.error('Failed to fetch groups:', error);
        }
      };
      fetchGroups();
    }
  }, [visible, roleType]);

  // Update group options when selected groups change
  useEffect(() => {
    if (roleType === RoleType.GROUP_SCOPED) {
      const isUserNotSelected = (g: string) => !selectedUserGroups.includes(g);
      const isDeviceNotSelected = (g: string) => !selectedDeviceGroups.includes(g);
      setUserGroupOptions(allUserGroups.filter(isUserNotSelected));
      setDeviceGroupOptions(allDeviceGroups.filter(isDeviceNotSelected));
    }
  }, [roleType, selectedUserGroups, selectedDeviceGroups, allUserGroups, allDeviceGroups]);

  if (!visible) return null;

  const leaveOnlySubmittable = (_: any, dom: JSX.Element[]) => dom.pop();

  // Helper function to render group selectors
  const renderGroupSelector = () => {
    if (roleType !== RoleType.GROUP_SCOPED) {
      return null;
    }

    return (
      <div style={{ marginBottom: 24 }}>
        <div style={{ marginBottom: 8 }}>
          <label className="ant-form-item-label">
            <span>{t('Scope', true)}</span>
          </label>
        </div>
        <Card size="small">
          <Space direction="vertical" style={{ width: '100%' }} size="middle">
            <div>
              <Typography.Text strong>{t('User Groups', true)}</Typography.Text>
              <Typography.Text type="secondary" style={{ display: 'block', fontSize: 12, marginBottom: 8 }}>
                {t('user_groups_scope_description', true)}
              </Typography.Text>
              <Select
                mode="multiple"
                showSearch
                allowClear
                placeholder={t('Select user groups', true) as string}
                value={selectedUserGroups}
                style={{ width: '100%' }}
                onDropdownVisibleChange={(open) => {
                  if (open) {
                    const isNotSelected = (g: string) => !selectedUserGroups.includes(g);
                    setUserGroupOptions(allUserGroups.filter(isNotSelected));
                  }
                }}
                onChange={(values) => {
                  setSelectedUserGroups(values);
                }}
              >
                {userGroupOptions.map((opt) => (
                  <Select.Option key={opt} value={opt}>
                    {opt}
                  </Select.Option>
                ))}
              </Select>
            </div>
            <div>
              <Typography.Text strong>{t('Device Groups', true)}</Typography.Text>
              <Typography.Text type="secondary" style={{ display: 'block', fontSize: 12, marginBottom: 8 }}>
                {t('device_groups_scope_description', true)}
              </Typography.Text>
              <Select
                mode="multiple"
                showSearch
                allowClear
                placeholder={t('Select device groups', true) as string}
                value={selectedDeviceGroups}
                style={{ width: '100%' }}
                onDropdownVisibleChange={(open) => {
                  if (open) {
                    const isNotSelected = (g: string) => !selectedDeviceGroups.includes(g);
                    setDeviceGroupOptions(allDeviceGroups.filter(isNotSelected));
                  }
                }}
                onChange={(values) => {
                  setSelectedDeviceGroups(values);
                }}
              >
                {deviceGroupOptions.map((opt) => (
                  <Select.Option key={opt} value={opt}>
                    {opt}
                  </Select.Option>
                ))}
              </Select>
            </div>
            <div>
              <Checkbox
                checked={includeUnassigned}
                onChange={(e) => setIncludeUnassigned(e.target.checked)}
              >
                {t('Unassigned devices', true)}
              </Checkbox>
              <Typography.Text type="secondary" style={{ display: 'block', fontSize: 12, marginLeft: 24 }}>
                {t('unassigned_devices_scope_description', true)}
              </Typography.Text>
            </div>
          </Space>
        </Card>
      </div>
    );
  };

  // Step 1: Role Name
  const roleNameTitle = t('Name', true);
  const roleNameFormItems = (
    <>
      <ProFormText
        name="name"
        label={t('Role Name', true)}
        initialValue={name}
        rules={[
          { required: true },
          { min: 4, max: 300 },
          {
            message: t('Role name already exists', true) as string,
            validator: (_, value) => {
              if (isNew && value && existingRoleNames.includes(value.trim())) {
                return Promise.reject();
              }
              return Promise.resolve();
            },
          },
        ]}
        placeholder={t('Role name', true) as string}
        fieldProps={{
          onChange: (evt) => setName(evt.target.value)
        }}
      />
      <ProFormSelect
        name="type"
        label={t('Type', true)}
        initialValue={roleType}
        rules={[{ required: true }]}
        disabled={!isNew}
        options={[
          { value: RoleType.GLOBAL, label: getRoleTypeName(RoleType.GLOBAL) },
          { value: RoleType.GROUP_SCOPED, label: getRoleTypeName(RoleType.GROUP_SCOPED) },
          { value: RoleType.INDIVIDUAL, label: getRoleTypeName(RoleType.INDIVIDUAL) },
        ]}
        fieldProps={{
          allowClear: false,
          onChange: (value) => {
            setRoleType(value as RoleType);
            // Clear selected groups when type changes
            setSelectedUserGroups([]);
            setSelectedDeviceGroups([]);
            setIncludeUnassigned(false);
            // Clear permissions when type changes as different types have different available permissions
            setPermissions([]);
          }
        }}
      />
      <Typography.Text type="secondary" style={{ display: 'block', marginTop: -16, marginBottom: 16 }}>
        {t(roleTypeDescriptions[roleType])}
      </Typography.Text>
      {renderGroupSelector()}
      <ProFormTextArea
        name="note"
        label={t('Note', true)}
        initialValue={note}
        rules={[
          { max: 300 }
        ]}
        placeholder={t('Optional note', true) as string}
        fieldProps={{
          rows: 3,
          onChange: (evt) => setNote(evt.target.value)
        }}
      />
    </>
  );
  const roleNameSubmitterRender = {
    searchConfig: { submitText: t(isNew ? 'Continue' : 'Save', true) },
    submitButtonProps: {
      disabled: name.length < 4 ||
        (roleType === RoleType.GROUP_SCOPED && selectedUserGroups.length === 0 && selectedDeviceGroups.length === 0 && !includeUnassigned),
      loading: loading,
    },
    render: leaveOnlySubmittable,
  };

  // Step 2: Permissions
  const rolePermsTitle = t('Permissions', true);
  const rolePermsFormItems = (
    <PermsFormItems
      permissions={permissions}
      setPermissions={setPermissions}
      autoAddRecommended={autoAddRecommended}
      onCountChange={setSelectedCount}
      roleType={roleType}
    />
  );
  const rolePermsSubmitterRender = {
    searchConfig: { submitText: t(isNew ? 'Create' : 'Save', true) },
    submitButtonProps: {
      loading: loading,
    },
    render: isNew ? (_: any, dom: JSX.Element[]) => {
      const submitButton = dom.pop();
      return [
        <div key="wrapper" style={{ display: 'flex', width: '100%', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <Checkbox
            checked={autoAddRecommended}
            onChange={(e) => {
              setAutoAddRecommended(e.target.checked);
              localStorage.setItem(ROLE_AUTO_ADD_RECOMMENDED_KEY, String(e.target.checked));
            }}
          >
            {t('Auto-add recommended permissions', true)}
          </Checkbox>
          <div style={{ display: 'flex', gap: '8px' }}>
            <Button onClick={() => setStep(RoleContent.RoleName)}>
              {t('Back', true)}
            </Button>
            {submitButton}
          </div>
        </div>
      ];
    } : (_: any, dom: JSX.Element[]) => {
      const submitButton = dom.pop();
      return [
        <div key="wrapper" style={{ display: 'flex', width: '100%', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <Checkbox
            checked={autoAddRecommended}
            onChange={(e) => {
              setAutoAddRecommended(e.target.checked);
              localStorage.setItem(ROLE_AUTO_ADD_RECOMMENDED_KEY, String(e.target.checked));
            }}
          >
            {t('Auto-add recommended permissions', true)}
          </Checkbox>
          {submitButton}
        </div>
      ];
    },
  };

  const stepItems = [
    { title: roleNameTitle },
    { title: rolePermsTitle }
  ];

  const formSteps: FormStep[] = [
    {
      formItems: roleNameFormItems,
      submitterProps: roleNameSubmitterRender,
    },
    {
      formItems: rolePermsFormItems,
      submitterProps: rolePermsSubmitterRender
    },
  ];

  const onFinishCreate = async () => {
    switch (step) {
      case RoleContent.RoleName:
        setStep(RoleContent.RolePerms);
        return false;
      case RoleContent.RolePerms:
        setLoading(true);
        const hide = message.loading(t('Creating'));
        try {
          await addAdminRole({
            data: {
              name,
              note,
              permissions,
              type: roleType,
              user_groups: selectedUserGroups,
              device_groups: selectedDeviceGroups,
              unassigned: roleType === RoleType.GROUP_SCOPED ? includeUnassigned : undefined,
            }
          });
          hide();
          message.success(t('Added successfully'));
          actionRef.current?.reload();
          onVisibleChange(false);
          return true;
        } catch (error) {
          hide();
          message.error(
            typeof error == 'string' ? error : t('Adding failed, please try again!')
          );
          return false;
        } finally {
          setLoading(false);
        }
      default:
        return false;
    }
  };

  const onFinishUpdate = async () => {
    setLoading(true);
    const hide = message.loading(t('Updating'));
    try {
      // Helper to compare arrays
      const arraysEqual = (a: any[], b: any[]) =>
        a.length === b.length && a.every((v, i) => v === b[i]);

      // Only include fields that have changed
      const data: {
        name?: string;
        note?: string;
        permissions?: number[];
        user_groups?: string[];
        device_groups?: string[];
        unassigned?: boolean;
      } = {};
      if (name !== (initialValues?.name ?? '')) {
        data.name = name;
      }
      if (note !== (initialValues?.note ?? '')) {
        data.note = note;
      }
      if (!arraysEqual(permissions, initialValues?.permissions ?? [])) {
        data.permissions = permissions;
      }
      // Send only the groups that changed (backend handles each type separately)
      const userGroupsChanged = !arraysEqual(selectedUserGroups, initialValues?.user_groups ?? []);
      const deviceGroupsChanged = !arraysEqual(selectedDeviceGroups, initialValues?.device_groups ?? []);
      if (userGroupsChanged) {
        data.user_groups = selectedUserGroups;
      }
      if (deviceGroupsChanged) {
        data.device_groups = selectedDeviceGroups;
      }
      if (includeUnassigned !== (initialValues?.unassigned ?? false)) {
        data.unassigned = includeUnassigned;
      }

      await updateAdminRole(initialValues?.guid!, { data });
      hide();
      message.success(t('Update is successful'));
      actionRef.current?.reload();
      onVisibleChange(false);
      return true;
    } catch (error) {
      hide();
      message.error(
        typeof error == 'string' ? error : t('Update failed, please try again!')
      );
      return false;
    } finally {
      setLoading(false);
    }
  };

  const onFinish = async () => isNew ? await onFinishCreate() : await onFinishUpdate();

  const handleTabChange = (activeKey: string) => {
    setStep(parseInt(activeKey));
  };

  // Custom title with selected count for permissions step
  const modalTitle = step === RoleContent.RolePerms ? (
    <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
      <span>{t(isNew ? 'Create Role' : 'Edit Role', true)}</span>
      <span style={{ fontSize: '14px', fontWeight: 'normal' }}>
        {t('Selected permissions', true)}: {selectedCount}
      </span>
    </div>
  ) : t(isNew ? 'Create Role' : 'Edit Role', true);

  return (
    <ModalForm
      formRef={formRef}
      title={modalTitle}
      open={visible}
      width={960}
      onOpenChange={onVisibleChange}
      submitter={formSteps[step].submitterProps}
      modalProps={{
        maskClosable: false,
        destroyOnClose: true,
      }}
      initialValues={isNew ? undefined : { name: initialValues?.name }}
      onFinish={onFinish}
    >
      {isNew ? (
        <Steps
          className={styles.stepsContainer}
          current={step}
          size="small"
          labelPlacement="vertical"
          items={stepItems}
        />
      ) : (
        <Tabs defaultActiveKey={step.toString()} onChange={handleTabChange} style={{ marginBottom: 0 }}>
          <Tabs.TabPane key={RoleContent.RoleName.toString()} tab={t('Overview', true)} />
          <Tabs.TabPane key={RoleContent.RolePerms.toString()} tab={t('Permissions', true)} />
        </Tabs>
      )}

      <div style={{
        padding: '0 18px 0 18px',
        maxHeight: 'calc(80vh - 200px)',
        overflowY: 'auto',
        overflowX: 'hidden'
      }}>
        {formSteps[step].formItems}
      </div>
    </ModalForm>
  );
};

export default NewOrUpdateForm;
