import { PlusOutlined, CheckOutlined } from '@ant-design/icons';
import { Button, message, Divider, Tag, Space, Tooltip, Breadcrumb } from 'antd';
import React, { useState, useRef, Fragment, useMemo, useCallback } from 'react';
import { PageContainer, FooterToolbar } from '@ant-design/pro-layout';
import type { ProColumns, ActionType } from '@ant-design/pro-table';
import ProTable from '@ant-design/pro-table';
import { adminRoles, deleteAdminRole } from '@/services/api';
import type { API } from '@/services/typings';
import { t, getTablePaginationConfig } from '../../global';
import NewOrUpdateForm, { parsePermId } from './NewOrUpdateForm';
import {
  Module,
  Level,
  RoleType,
} from './permissionUtils';
import { getLocalSortState, handleSortStateChange } from '@/components/Others/table_sort';
import MyModalConfirm from '@/components/Others/MyModalConfirm';
import UsersModal from './UsersModal';
import { Link } from '@umijs/max';

export const ROLE_LIST_SORT_STATE_KEY = 'role_list_sort_state';

/**
 * Permission Display Functions
 *
 * IMPORTANT: All mappings in this file must stay in sync with backend src/role.rs:
 * - Module IDs and names
 * - Permission levels (VIEW, EDIT, and fine-grained operations)
 *
 * Any changes to role.rs constants must be reflected here.
 *
 */

const handleDelete = async (rows: API.AdminRoleListItem[]) => {
  const hide = message.loading(t('Deleting'));
  try {
    await deleteAdminRole({
      data: {
        guids: rows.map((x) => x.guid),
      },
    });
    hide();
    message.success('Deletion is successful');
    return true;
  } catch (error) {
    hide();
    message.error(
      typeof error == 'string' ? (error as string) : 'Deletion failed, please try again!',
    );
    return false;
  }
};

/**
 * Get role type name - MUST be called inside React component
 * (uses t() with useIntl Hook)
 */
export const getRoleTypeName = (roleType: number): string => {
  switch (roleType) {
    case RoleType.GLOBAL:
      return t('Global', true) as string;
    case RoleType.INDIVIDUAL:
      return t('Individual', true) as string;
    case RoleType.GROUP_SCOPED:
      return t('Group Scoped', true) as string;
    default:
      return `Type ${roleType}`;
  }
};

/**
 * Complete permission level name mapping
 * Must stay in sync with role.rs level definitions
 * Note: This function should only be called inside React components!
 */
const getLevelName = (level: number, module?: number): { name: string; color: string } => {
  // Standard permission levels (applicable to all modules)
  if (level === Level.VIEW) {
    return { name: t('View', true) as string, color: 'blue' };
  }
  if (level === Level.EDIT) {
    return { name: t('Edit', true) as string, color: 'green' };
  }

  // Module-specific fine-grained levels
  if (module === Module.USERS) {
    switch (level) {
      case Level.USER_CREATE:
        return { name: t('Create', true) as string, color: 'cyan' };
      case Level.USER_INVITE:
        return { name: t('Invite', true) as string, color: 'cyan' };
      case Level.USER_DELETE:
        return { name: t('Delete', true) as string, color: 'cyan' };
      case Level.USER_ENABLE_DISABLE:
        return { name: t('Enable/Disable', true) as string, color: 'cyan' };
      case Level.USER_EDIT_EMAIL:
        return { name: t('Edit Email', true) as string, color: 'cyan' };
      case Level.USER_EDIT_PASSWORD:
        return { name: t('Edit Password', true) as string, color: 'cyan' };
      case Level.USER_EDIT_NOTE:
        return { name: t('Edit Note', true) as string, color: 'cyan' };
      case Level.USER_EDIT_DISPLAY_NAME:
        return { name: t('Edit Display Name', true) as string, color: 'cyan' };
      case Level.USER_MANAGE_2FA:
        return { name: t('Manage 2FA', true) as string, color: 'cyan' };
      case Level.USER_FORCE_LOGOUT:
        return { name: t('Force Logout', true) as string, color: 'cyan' };
      case Level.USER_CHANGE_GROUP:
        return { name: t('Update Group', true) as string, color: 'cyan' };
      case Level.USER_CHANGE_STRATEGY:
        return { name: t('Update Strategy', true) as string, color: 'cyan' };
      case Level.USER_CHANGE_CONTROL_ROLE:
        return { name: t('Update Control Role', true) as string, color: 'cyan' };
    }
  }

  if (module === Module.DEVICES) {
    switch (level) {
      case Level.DEVICE_ENABLE_DISABLE:
        return { name: t('Enable/Disable', true) as string, color: 'purple' };
      case Level.DEVICE_DELETE:
        return { name: t('Delete', true) as string, color: 'purple' };
      case Level.DEVICE_EDIT_INFO:
        return { name: t('Edit Info', true) as string, color: 'purple' };
      case Level.DEVICE_ASSIGN_TO_USER:
        return { name: t('Assign to User', true) as string, color: 'purple' };
      case Level.DEVICE_CHANGE_GROUP:
        return { name: t('Update Group', true) as string, color: 'purple' };
      case Level.DEVICE_CHANGE_STRATEGY:
        return { name: t('Update Strategy', true) as string, color: 'purple' };
    }
  }

  if (module === Module.DEVICE_GROUPS) {
    if (level === Level.DEVICE_GROUP_CHANGE_STRATEGY) {
      return { name: t('Update Strategy', true) as string, color: 'orange' };
    }
  }

  // Unknown level
  return { name: `Level 0x${level.toString(16).toUpperCase()}`, color: 'default' };
};

/**
 * Render permission tag with module-aware level display
 * Memoized component to prevent unnecessary re-renders
 */
const PermissionTag = React.memo<{ level: number; module?: number }>(({ level, module }) => {
  const { name: levelName, color } = getLevelName(level, module);
  return <Tag color={color}>{levelName}</Tag>;
});
PermissionTag.displayName = 'PermissionTag';

/**
 * Render all permissions for a role
 * Optimized with memoization
 */
const RolePermissions = React.memo<{ record: API.AdminRoleListItem }>(({ record }) => {
  const permIds = record.permissions || [];

  // Cache module name mapping inside component (uses useIntl hook)
  const moduleMap = useMemo<Record<number, string>>(() => ({
    [Module.USERS]: t('Users', true) as string,
    [Module.DEVICES]: t('Devices', true) as string,
    [Module.USER_GROUPS]: t('User Groups', true) as string,
    [Module.DEVICE_GROUPS]: t('Device Groups', true) as string,
    [Module.AUDIT_LOGS]: t('Logs', true) as string,
    [Module.STRATEGIES]: t('Strategies', true) as string,
    [Module.CONTROL_ROLES]: t('Control Roles', true) as string,
    [Module.CUSTOM_CLIENTS]: t('Custom Clients', true) as string,
  }), []);

  // Use useMemo to cache the heavy computation
  const groupedPerms = useMemo(() => {

    // Group permissions by module
    const permsMap: Record<number, Array<{ level: number }>> = {};
    permIds.forEach((permId: number) => {
      const { module, level } = parsePermId(permId);
      if (!permsMap[module]) {
        permsMap[module] = [];
      }
      permsMap[module].push({ level });
    });

    // Sort by module ID
    const sortedModules = Object.keys(permsMap)
      .map(Number)
      .sort((a, b) => a - b);

    return sortedModules.map(moduleId => {
      const perms = permsMap[moduleId].sort((a, b) => a.level - b.level);
      const moduleName = moduleMap[moduleId] || `Module ${moduleId}`;
      return { moduleId, perms, moduleName };
    });
  }, [permIds, moduleMap]);

  return (
    <Space direction="vertical" size="small">
      {groupedPerms.map(({ moduleId, perms, moduleName }) => {
        const tags = perms.map((perm, index) => (
          <PermissionTag
            key={`${moduleId}-${perm.level}-${index}`}
            level={perm.level}
            module={moduleId}
          />
        ));

        if (tags.length > 0) {
          return (
            <div key={moduleId}>
              <span style={{ marginRight: 8, fontWeight: 500 }}>{moduleName}:</span>
              <Space size="small" wrap>{tags}</Space>
            </div>
          );
        }

        return null;
      })}
    </Space>
  );
});
RolePermissions.displayName = 'RolePermissions';

/**
 * Memoized Groups Display Component
 */
const RoleGroups = React.memo<{ record: API.AdminRoleListItem }>(({ record }) => {
  // Only show groups for Group type
  if (record.type !== RoleType.GROUP_SCOPED) {
    return <span style={{ color: '#999' }}>-</span>;
  }

  const hasUserGroups = record.user_groups && record.user_groups.length > 0;
  const hasDeviceGroups = record.device_groups && record.device_groups.length > 0;

  if (!hasUserGroups && !hasDeviceGroups && !record.unassigned) {
    return <span style={{ color: '#999' }}>-</span>;
  }

  return (
    <Space direction="vertical" size="small">
      {hasUserGroups && (
        <div>
          <span style={{ marginRight: 4, color: '#666' }}>{t('User Groups', true)}:</span>
          <Space size="small" wrap>
            {record.user_groups!.map((group, index) => (
              <Tag key={`u-${index}`} color="blue">{group}</Tag>
            ))}
          </Space>
        </div>
      )}
      {hasDeviceGroups && (
        <div>
          <span style={{ marginRight: 4, color: '#666' }}>{t('Device Groups', true)}:</span>
          <Space size="small" wrap>
            {record.device_groups!.map((group, index) => (
              <Tag key={`d-${index}`} color="green">{group}</Tag>
            ))}
          </Space>
        </div>
      )}
      {record.unassigned && (
        <div>
          <span style={{ marginRight: 4, color: '#666' }}>{t('Unassigned devices', true)}:</span>
          <CheckOutlined style={{ color: '#52c41a' }} />
        </div>
      )}
    </Space>
  );
});
RoleGroups.displayName = 'RoleGroups';

const DeleteRoles = React.memo<{ children: any; onClick: () => void }>(({ children, onClick }) => (
  <MyModalConfirm
    title={t('deleteConfirm', true, 'Are you sure to delete?')}
    onConfirm={onClick}
    okText="Yes"
    cancelText="No"
  >
    {children}
  </MyModalConfirm>
));
DeleteRoles.displayName = 'DeleteRoles';

const TableList: React.FC = () => {
  const [createModalVisible, handleModalVisible] = useState<boolean>(false);
  const [updateModalVisible, handleUpdateModalVisible] = useState<boolean>(false);
  const [usersModalVisible, setUsersModalVisible] = useState<boolean>(false);
  const [usersModalItem, setUsersModalItem] = useState<API.AdminRoleListItem>();

  const actionRef = useRef<ActionType>();
  const [currentRow, setCurrentRow] = useState<API.AdminRoleListItem>();
  const [selectedRowsState, setSelectedRows] = useState<API.AdminRoleListItem[]>([]);
  const [sortState, setSortState] = useState<API.SortState>(() => getLocalSortState(ROLE_LIST_SORT_STATE_KEY));

  // Memoize delete handler
  const handleDeleteClick = useCallback(async (record: API.AdminRoleListItem) => {
    setCurrentRow(record);
    await handleDelete([record]);
    actionRef.current?.reloadAndRest?.();
  }, []);

  const handleBatchDeleteClick = useCallback(async () => {
    await handleDelete(selectedRowsState);
    setSelectedRows([]);
    actionRef.current?.reloadAndRest?.();
  }, [selectedRowsState]);

  const handleEditClick = useCallback((record: API.AdminRoleListItem) => {
    setCurrentRow(record);
    handleUpdateModalVisible(true);
  }, []);

  // Memoize columns to prevent recreating on every render
  const columns: ProColumns<API.AdminRoleListItem>[] = useMemo(() => [
    {
      title: t('Name'),
      dataIndex: 'name',
      key: 'name',
      sorter: true,
      sortOrder: sortState.columnKey === 'name' ? sortState.order : undefined,
      showSorterTooltip: false,
    },
    {
      title: t('Type', true),
      dataIndex: 'type',
      width: 150,
      sorter: true,
      sortOrder: sortState.columnKey === 'type' ? sortState.order : undefined,
      showSorterTooltip: false,
      valueEnum: {
        [RoleType.GLOBAL]: { text: t('Global', true) },
        [RoleType.INDIVIDUAL]: { text: t('Individual', true) },
        [RoleType.GROUP_SCOPED]: { text: t('Group Scoped', true) },
      },
    },
    {
      title: t('Scope', true),
      dataIndex: 'groups',
      search: false,
      render: (_, record) => <RoleGroups record={record} />,
    },
    {
      title: t('Permissions', true),
      dataIndex: 'permissions',
      search: false,
      render: (_, record) => <RolePermissions record={record} />,
    },
    {
      title: `#${t('Users', true)}`,
      dataIndex: 'user_count',
      search: false,
      width: 150,
      render: (_, record) => {
        const count = record.user_count || 0;
        return (
          <Tooltip title={t('Click to view users', true)}>
            <Link to={`/roles/admin/${record.guid}/users`} style={{ padding: '8px 12px', margin: '-8px -12px' }}>{count}</Link>
          </Tooltip>
        );
      },
    },
    {
      title: t('Note'),
      dataIndex: 'note',
      key: 'note',
      width: 150,
      sorter: true,
      sortOrder: sortState.columnKey === 'note' ? sortState.order : undefined,
      showSorterTooltip: false,
    },
    {
      title: t('Action'),
      search: false,
      render: (text, record) => (
        <Fragment>
          <a onClick={() => handleEditClick(record)}>
            {t('Edit')}
          </a>
          <Divider type="vertical" />
          <a onClick={() => { setUsersModalItem(record); setUsersModalVisible(true); }}>
            {t('Assign Users')}
          </a>
          <Divider type="vertical" />
          <DeleteRoles onClick={() => handleDeleteClick(record)}>
            <a style={{ color: 'red' }}>{t('Delete')}</a>
          </DeleteRoles>
        </Fragment>
      ),
    },
  ], [sortState, handleEditClick, handleDeleteClick]);

  return (
    <PageContainer
      breadcrumbRender={() => (
        <Breadcrumb items={[
          { title: t('menu.list.role-list', true) },
          { title: t('menu.list.role-list.admin', true) },
        ]} />
      )}
    >
      <ProTable<API.AdminRoleListItem, API.PageParams>
        headerTitle={t('Role List', true)}
        columnsState={{ persistenceType: 'localStorage', persistenceKey: 'role_list_columns_state' }}
        actionRef={actionRef}
        rowKey="guid"
        search={{
          labelWidth: 120,
        }}
        toolBarRender={() => [
          <Button
            type="primary"
            key="primary"
            onClick={() => {
              handleModalVisible(true);
            }}
          >
            <PlusOutlined /> {t('Create')}
          </Button>,
        ]}
        request={async (params) => {
          const res = await adminRoles(params, undefined, undefined, sortState);
          return res;
        }}
        columns={columns}
        rowSelection={{
          onChange: (_, selectedRows) => {
            setSelectedRows(selectedRows);
          },
        }}
        pagination={getTablePaginationConfig("role_list")}
        onChange={(_, __, sorter) => {
          handleSortStateChange(sorter, actionRef, ROLE_LIST_SORT_STATE_KEY, setSortState);
        }}
      />
      {selectedRowsState?.length > 0 && (
        <FooterToolbar
          extra={
            <div>
              {t('Chosen')} <a style={{ fontWeight: 600 }}>{selectedRowsState.length}</a>{' '}
              {t('Items')}
            </div>
          }
        >
          <DeleteRoles onClick={handleBatchDeleteClick}>
            <Button>{t('Delete')}</Button>
          </DeleteRoles>
        </FooterToolbar>
      )}
      {createModalVisible && (
        <NewOrUpdateForm
          isNew={true}
          visible={createModalVisible}
          onVisibleChange={handleModalVisible}
          actionRef={actionRef}
          initialValues={undefined}
        />
      )}
      {updateModalVisible && (
        <NewOrUpdateForm
          isNew={false}
          visible={updateModalVisible}
          onVisibleChange={handleUpdateModalVisible}
          actionRef={actionRef}
          initialValues={currentRow || undefined}
        />
      )}
      {usersModalItem && usersModalVisible && (
        <UsersModal
          visible={usersModalVisible}
          setVisible={setUsersModalVisible}
          adminRoleGuid={usersModalItem.guid}
          adminRoleName={usersModalItem.name}
          closeChangedCallback={() => actionRef.current?.reload()}
        />
      )}
    </PageContainer>
  );
};

export default TableList;
